import { View, StyleSheet } from "react-native";
import React, { useState, useContext } from 'react';
import { ProgressContext, UserContext } from '../contexts';
import { WebView } from 'react-native-webview';
import axios from 'axios';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useNavigation } from "@react-navigation/native";

const REST_API_KEY = '9fd6d6c300b1e8d443843c3301a50ac5';
const REDIRECT_URI = 'http://192.168.1.102:19006';
const INJECTED_JAVASCRIPT = `window.ReactNativeWebView.postMessage('message from webView')`;


const KaKaoLogin = () => {
  const { dispatch } = useContext(UserContext);


  const navigation = useNavigation();

  function KakaoLoginWebView (data) {
    const exp = "code=";
    var condition = data.indexOf(exp);    
    if (condition != -1) {
      var authorize_code = data.substring(condition + exp.length);
      //console.log(authorize_code);
      requestToken(authorize_code);
    };
  }

  const requestToken = async (authorize_code) => {
    var AccessToken = "none";
    axios ({
      method: 'post',
      url: 'https://kauth.kakao.com/oauth/token',
      params: {
        grant_type: 'authorization_code',
        client_id: REST_API_KEY,
        redirect_uri: REDIRECT_URI,
        code: authorize_code,
      },
    }).then((response) => {
      AccessToken = response.data.access_token;
      //console.log(AccessToken);
      //requestUserInfo(AccessToken);
      storeData(AccessToken);
    }).catch(function (error) {
      console.log('error', error);
    })
    //const user = {user: {email : "sdf", uid : "sdfg", jeong : null, start_year : null}};
      dispatch({"_redirectEventId": undefined, "apiKey": "AIzaSyBm6_m3rU_FhHJZsS8sXPZ2pJXXxqZdUdc", "appName": "[DEFAULT]", "createdAt": "1689524636342", "displayName": undefined, "email": "gaonnurirtg@hanmail.net", "emailVerified": false, "isAnonymous": false, "lastLoginAt": "1693155835038", "phoneNumber": undefined, "photoURL": undefined, "providerData": [[Object]], "stsTokenManager": {"accessToken": "eyJhbGciOiJSUzI1NiIsImtpZCI6ImM2MGI5ZGUwODBmZmFmYmZjMTgzMzllY2Q0NGFjNzdmN2ZhNGU4ZDMiLCJ0eXAiOiJKV1QifQ..cuUCTkMSZV8qO9dVHWxt7G17XYLDFUp1Zn8JEUUri5pXCkHqLMt3jYN4q5R-aRysENoG646PyOdS2GaeNdq5_xPsxQxndf8qUyuO-eMMTvP3Wt1I6u_5cHjEluRFjrLcGW6sBT7suKkiddr7MgMDubTUTremwOT9hgx-KQEGRJFnGhih_cOxBlMet2k-LLDw4hSjUwAVXc9mlNTYZ6Yd4Kz2hq_6qtz04GpFO7qSY7jNQN7-RnloaoujH79rBJEj005lKmZC3UCCXDm2XQ4dtlQ4Ja2JeurhG86AdBZ-dM-W2NMP5m6Mqv7Jwxkc2XyRTcfbmIR21b0NvwqU5aCa-w", "expirationTime": 1693159435586, "refreshToken": "AMf-vByEbGlbl_iC5xIvYDU6iAQjMtf36ySplutqaPjY4YWn60X6vFv3ql1agNffUZ7OHPwabdPRh-MoXvMPxtfl_Y16i5L1xjVcv0YIRWxah758KDWd-fBAemQDqCgcCnwlpvpbqCfOIppFu_T6LB8XEMLfdNHaZ2-tiJ_J88jLfE-49Gt_G2VJ-J9jRXrL7RjeIKVAC1kwmcvNkwa9lrEwyVRUB7I9gw"}, "tenantId": undefined, "uid": "aGGruLvYuKdjAnthhudRXqPqCxm1"});
    //navigation.navigate("MyPage", { screen: "MyPage" } );
  };

  // function requestUserInfo(AccessToken)  {
  //   axios ({
  //     method: 'GET',
  //     url: 'https://kapi.kakao.com/v2/user/me',
  //     headers: {
  //       Authorization : `Bearer ${AccessToken}`
  //     },
  //   }).then((response) => {
  //     var user_emil = response.data.kakao_account.email;
  //     var user_range = response.data.kakao_account.age_range;
  //     var user_gender = response.data.kakao_account.gender;
  //     console.log("user_emil", user_emil);
  //     console.log("user_range", user_range);
  //     console.log("user_gender", user_gender);
  //   }).catch(function (error) {
  //     console.log('error', error);
  //   })
  //   return;
  // }

  const storeData = async (returnValue) => {
    try {
      await AsyncStorage.setItem('userAccessToken', returnValue);
    } catch (error) {
    }
  }

  return (
    <View style={Styles.container}>      
      <WebView
        style={{ flex: 1 }}
        originWhitelist={['*']}
        scalesPageToFit={false}
        source={{
          uri: `https://kauth.kakao.com/oauth/authorize?response_type=code&client_id=${REST_API_KEY}&redirect_uri=${REDIRECT_URI}`,
        }}
        injectedJavaScript={INJECTED_JAVASCRIPT}
        javaScriptEnabled
        onMessage={event => { KakaoLoginWebView(event.nativeEvent["url"]); }}
      />
    </View>
  )
}

export default KaKaoLogin;

const Styles = StyleSheet.create({
  container: {
    flex: 1,
    marginTop: 24,
    backgroundColor: '#fff',
  },    
});
